mapper.select:
SELECT USR.USER_ID, USR.LOGIN_ID, USR.USER_NM AS USER_NAME, USR.USER_TYPE_CD, USR.DEPT_TEAM_CD AS DEPARTMENT_CD, USR.MOBILE_PHONE_NUM, USR.TEL_NUM, USR.EMAIL, USR.APPROVAL_TYPE_CD, USR.USER_STATUS_CD, (CASE WHEN USR.APPROVAL_TYPE_CD = 'Z' THEN '미신청' ELSE (SELECT CD_NM END FROM TB_CODE_CD WHERE CD = USR.APPROVAL_TYPE_CD AND CATEGORY_CD = 'APPROVAL_TYPE' AND LVL='1') END) APPROVAL_TYPE_NM, ORG.CONN_ALLOW_YN_CD, ORG.ORG_NM AS DEPARTMENT_NAME, ORG.TEAM_TYPE_CD, ORG.HIGHER_ORG_ID, TO_CHAR(USR.LAST_APPROACH_TIME, 'YYYY-MM-DD HH24:MI:SS') AS LAST_APPROACH_TIME , USR.TITL_TYPE_CD , '' AS ORG_CONFIRM FROM TB_USER_MST USR LEFT OUTER JOIN TB_ORG_MST ORG ON USR.DEPT_TEAM_CD = ORG.ORG_ID WHERE USR.USER_STATUS_CD IN ('U', 'X')
AND USR.USER_ID = #{USER_ID}
AND USR.LOGIN_ID = #{LOGIN_ID}
AND 1=2
AND ROWNUM = 1
